let daniel_hashed_name="307f553de10228735f047229c1abc64fc001627af13665c1e7e695a2b589f578";async function hashText(e){e=await crypto.subtle.digest("SHA-256",(new TextEncoder).encode(e));return Array.from(new Uint8Array(e)).map(e=>e.toString(16).padStart(2,"0")).join("")}$("#main input").on("input",function(){hashText($(this).val()).then(e=>{e===daniel_hashed_name&&($("#main").slideUp(600),setTimeout(()=>{fetch("../daniel.txt").then(e=>e.text()).then(e=>{$("#main").text(e).addClass("logged").slideDown(600)})},1500))})});